   620→// This fetches the transcript from entire/checkpoints/v1 and writes it to Claude's project directory.
   621→// Does not modify the working directory.
   622→// When multiple sessions were condensed to the same checkpoint, ALL sessions are restored.
   623→// If force is false, prompts for confirmation when local logs have newer timestamps.
   624→func (s *ManualCommitStrategy) RestoreLogsOnly(point RewindPoint, force bool) error {
   625→	if !point.IsLogsOnly {
   626→		return errors.New("not a logs-only rewind point")
   627→	}
   628→
   629→	if point.CheckpointID.IsEmpty() {
   630→		return errors.New("missing checkpoint ID")
   631→	}
   632→
   633→	// Get checkpoint store
   634→	store, err := s.getCheckpointStore()
   635→	if err != nil {
   636→		return fmt.Errorf("failed to get checkpoint store: %w", err)
   637→	}
   638→
   639→	// Read checkpoint summary to get session count
   640→	summary, err := store.ReadCommitted(context.Background(), point.CheckpointID)
   641→	if err != nil {
   642→		return fmt.Errorf("failed to read checkpoint: %w", err)
   643→	}
   644→	if summary == nil {
   645→		return fmt.Errorf("checkpoint not found: %s", point.CheckpointID)
   646→	}
   647→
   648→	// Get repo root for Claude project path lookup
   649→	repoRoot, err := paths.RepoRoot()
   650→	if err != nil {
   651→		return fmt.Errorf("failed to get repository root: %w", err)
   652→	}
   653→
   654→	claudeProjectDir, err := paths.GetClaudeProjectDir(repoRoot)
   655→	if err != nil {
   656→		return fmt.Errorf("failed to get Claude project directory: %w", err)
   657→	}
   658→
   659→	// Ensure project directory exists
   660→	if err := os.MkdirAll(claudeProjectDir, 0o750); err != nil {
   661→		return fmt.Errorf("failed to create Claude project directory: %w", err)
   662→	}
   663→
   664→	// Check for newer local logs if not forcing
   665→	if !force {
   666→		sessions := s.classifySessionsForRestore(context.Background(), claudeProjectDir, store, point.CheckpointID, summary)
   667→		hasConflicts := false
   668→		for _, sess := range sessions {
   669→			if sess.Status == StatusLocalNewer {
   670→				hasConflicts = true
   671→				break
   672→			}
   673→		}
   674→		if hasConflicts {
   675→			shouldOverwrite, promptErr := PromptOverwriteNewerLogs(sessions)
   676→			if promptErr != nil {
   677→				return promptErr
   678→			}
   679→			if !shouldOverwrite {
   680→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session logs preserved.\n")
   681→				return nil
   682→			}
   683→		}
   684→	}
   685→
   686→	// Count sessions to restore
   687→	totalSessions := len(summary.Sessions)
   688→	if totalSessions > 1 {
   689→		fmt.Fprintf(os.Stderr, "Restoring %d sessions from checkpoint:\n", totalSessions)
   690→	}
   691→
   692→	// Restore all sessions (oldest to newest, using 0-based indexing)
   693→	for i := range totalSessions {
   694→		content, readErr := store.ReadSessionContent(context.Background(), point.CheckpointID, i)
   695→		if readErr != nil {
   696→			fmt.Fprintf(os.Stderr, "  Warning: failed to read session %d: %v\n", i, readErr)
   697→			continue
   698→		}
   699→		if content == nil || len(content.Transcript) == 0 {
   700→			continue
   701→		}
   702→
   703→		sessionID := content.Metadata.SessionID
   704→		if sessionID == "" {
   705→			// Fallback: can't identify session without ID
   706→			fmt.Fprintf(os.Stderr, "  Warning: session %d has no session ID, skipping\n", i)
   707→			continue
   708→		}
   709→
   710→		modelSessionID := sessionid.ModelSessionID(sessionID)
   711→		claudeSessionFile := filepath.Join(claudeProjectDir, modelSessionID+".jsonl")
   712→
   713→		// Get first prompt for display
   714→		promptPreview := ExtractFirstPrompt(content.Prompts)
   715→
   716→		if totalSessions > 1 {
   717→			isLatest := i == totalSessions-1
   718→			if promptPreview != "" {
   719→				if isLatest {
   720→					fmt.Fprintf(os.Stderr, "  Session %d (latest): %s\n", i+1, promptPreview)
   721→				} else {
   722→					fmt.Fprintf(os.Stderr, "  Session %d: %s\n", i+1, promptPreview)
   723→				}
   724→			}
   725→			fmt.Fprintf(os.Stderr, "    Writing to: %s\n", claudeSessionFile)
   726→		} else {
   727→			fmt.Fprintf(os.Stderr, "Writing transcript to: %s\n", claudeSessionFile)
   728→		}
   729→
   730→		if writeErr := os.WriteFile(claudeSessionFile, content.Transcript, 0o600); writeErr != nil {
   731→			if totalSessions > 1 {
   732→				fmt.Fprintf(os.Stderr, "    Warning: failed to write transcript: %v\n", writeErr)
   733→				continue
   734→			}
   735→			return fmt.Errorf("failed to write transcript: %w", writeErr)
   736→		}
   737→	}
   738→
   739→	return nil
   740→}
