   221→// WriteSession writes a session to Gemini's storage (JSON transcript file).
   222→// Uses the NativeData field which contains raw JSON bytes.
   223→func (g *GeminiCLIAgent) WriteSession(session *agent.AgentSession) error {
   224→	if session == nil {
   225→		return errors.New("session is nil")
   226→	}
   227→
   228→	// Verify this session belongs to Gemini CLI
   229→	if session.AgentName != "" && session.AgentName != g.Name() {
   230→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, g.Name())
   231→	}
   232→
   233→	if session.SessionRef == "" {
   234→		return errors.New("session reference (transcript path) is required")
