			return &protectedDirAgent{dirs: []string{".shared"}}
		})

		dirs := AllProtectedDirs()
		if len(dirs) != 1 {
			t.Errorf("expected 1 dir (deduplicated), got %d: %v", len(dirs), dirs)
		}
	})
}

