    51→// DetectPresence checks if Gemini CLI is configured in the repository.
    52→func (g *GeminiCLIAgent) DetectPresence() (bool, error) {
    53→	// Get repo root to check for .gemini directory
    54→	// This is needed because the CLI may be run from a subdirectory
    55→	repoRoot, err := paths.RepoRoot()
    56→	if err != nil {
    57→		// Not in a git repo, fall back to CWD-relative check
    58→		repoRoot = "."
    59→	}
    60→
    61→	// Check for .gemini directory
    62→	geminiDir := filepath.Join(repoRoot, ".gemini")
    63→	if _, err := os.Stat(geminiDir); err == nil {
    64→		return true, nil
    65→	}
    66→	// Check for .gemini/settings.json
    67→	settingsFile := filepath.Join(repoRoot, ".gemini", "settings.json")
    68→	if _, err := os.Stat(settingsFile); err == nil {
    69→		return true, nil
    70→	}
    71→	return false, nil
    72→}
