   214→		modifiedFiles = nil
   215→	}
   216→
   217→	return &agent.AgentSession{
   218→		SessionID:     input.SessionID,
   219→		AgentName:     g.Name(),
   220→		SessionRef:    input.SessionRef,
   221→		StartTime:     time.Now(),
   222→		NativeData:    data,
   223→		ModifiedFiles: modifiedFiles,
   224→	}, nil
   225→}
