   270→// GetTranscriptPosition returns the current message count of a Gemini transcript.
   271→// Gemini uses JSON format with a messages array, so position is the message count.
   272→// Returns 0 if the file doesn't exist or is empty.
   273→func (g *GeminiCLIAgent) GetTranscriptPosition(path string) (int, error) {
   274→	if path == "" {
   275→		return 0, nil
   276→	}
   277→
   278→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
   279→	if err != nil {
   280→		if os.IsNotExist(err) {
   281→			return 0, nil
   282→		}
   283→		return 0, fmt.Errorf("failed to read transcript: %w", err)
   284→	}
   285→
   286→	if len(data) == 0 {
   287→		return 0, nil
   288→	}
   289→
   290→	transcript, err := ParseTranscript(data)
   291→	if err != nil {
   292→		return 0, fmt.Errorf("failed to parse transcript: %w", err)
   293→	}
   294→
   295→	return len(transcript.Messages), nil
   296→}
