   372→// TranscriptChunker interface implementation
   373→
   374→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
   375→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
   376→// the messages array while preserving the JSON structure in each chunk.
   377→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
   378→	var transcript GeminiTranscript
   379→	if err := json.Unmarshal(content, &transcript); err != nil {
   380→		// Fall back to JSONL chunking if not valid Gemini JSON
   381→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
   382→		if chunkErr != nil {
   383→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
   384→		}
   385→		return chunks, nil
   386→	}
   387→
   388→	if len(transcript.Messages) == 0 {
   389→		return [][]byte{content}, nil
   390→	}
   391→
   392→	var chunks [][]byte
   393→	var currentMessages []GeminiMessage
   394→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
   395→
   396→	for i, msg := range transcript.Messages {
   397→		// Marshal message to get its size
   398→		msgBytes, err := json.Marshal(msg)
   399→		if err != nil {
   400→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
   401→				slog.Int("message_index", i),
   402→				slog.String("error", err.Error()),
   403→			)
   404→			continue
   405→		}
   406→		msgSize := len(msgBytes) + 1 // +1 for comma separator
   407→
   408→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
   409→			// Save current chunk
   410→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   411→			if err != nil {
   412→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
   413→			}
   414→			chunks = append(chunks, chunkData)
   415→
   416→			// Start new chunk
   417→			currentMessages = nil
   418→			currentSize = len(`{"messages":[]}`)
   419→		}
   420→
   421→		currentMessages = append(currentMessages, msg)
   422→		currentSize += msgSize
   423→	}
   424→
   425→	// Add the last chunk
   426→	if len(currentMessages) > 0 {
   427→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
   428→		if err != nil {
   429→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
   430→		}
   431→		chunks = append(chunks, chunkData)
   432→	}
   433→
   434→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
   435→	if len(chunks) == 0 {
   436→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
   437→	}
   438→
   439→	return chunks, nil
   440→}
   441→
   442→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
   443→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
   444→	var allMessages []GeminiMessage
   445→
   446→	for _, chunk := range chunks {
   447→		var transcript GeminiTranscript
   448→		if err := json.Unmarshal(chunk, &transcript); err != nil {
   449→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
   450→		}
   451→		allMessages = append(allMessages, transcript.Messages...)
   452→	}
   453→
   454→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
   455→	if err != nil {
   456→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
   457→	}
   458→	return result, nil
   459→}
