   147→// CountOtherActiveSessionsWithCheckpoints counts how many other active sessions
   148→// from the SAME worktree (different from currentSessionID) have created checkpoints
   149→// on the SAME base commit (current HEAD). This is used to show an informational message
   150→// about concurrent sessions that will be included in the next commit.
   151→// Returns 0, nil if no such sessions exist.
   152→func (s *ManualCommitStrategy) CountOtherActiveSessionsWithCheckpoints(currentSessionID string) (int, error) {
   153→	currentWorktree, err := GetWorktreePath()
   154→	if err != nil {
   155→		return 0, err
   156→	}
   157→
   158→	// Get current HEAD to compare with session base commits
   159→	repo, err := OpenRepository()
   160→	if err != nil {
   161→		return 0, err
   162→	}
   163→	head, err := repo.Head()
   164→	if err != nil {
   165→		return 0, fmt.Errorf("failed to get HEAD: %w", err)
   166→	}
   167→	currentHead := head.Hash().String()
   168→
   169→	allStates, err := s.listAllSessionStates()
   170→	if err != nil {
   171→		return 0, err
   172→	}
   173→
   174→	count := 0
   175→	for _, state := range allStates {
   176→		// Only consider sessions from the same worktree with checkpoints
   177→		// AND based on the same commit (current HEAD)
   178→		// Sessions from different base commits are independent and shouldn't be counted
   179→		if state.SessionID != currentSessionID &&
   180→			state.WorktreePath == currentWorktree &&
   181→			state.StepCount > 0 &&
   182→			state.BaseCommit == currentHead {
   183→			count++
   184→		}
   185→	}
   186→	return count, nil
   187→}
