   231→		AgentType:             agentType,
   232→		TranscriptPath:        transcriptPath,
   233→		FirstPrompt:           truncatePromptForStorage(userPrompt),
   234→	}
   235→
   236→	if err := s.saveSessionState(state); err != nil {
   237→		return nil, err
   238→	}
   239→
   240→	return state, nil
   241→}
