    84→// ParseHookInput parses Gemini CLI hook input from stdin.
    85→func (g *GeminiCLIAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
    86→	data, err := io.ReadAll(reader)
    87→	if err != nil {
    88→		return nil, fmt.Errorf("failed to read input: %w", err)
    89→	}
    90→
    91→	if len(data) == 0 {
    92→		return nil, errors.New("empty input")
    93→	}
    94→
    95→	input := &agent.HookInput{
    96→		HookType:  hookType,
    97→		Timestamp: time.Now(),
    98→		RawData:   make(map[string]interface{}),
    99→	}
   100→
   101→	// Parse based on hook type
   102→	switch hookType {
   103→	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
   104→		var raw sessionInfoRaw
   105→		if err := json.Unmarshal(data, &raw); err != nil {
   106→			return nil, fmt.Errorf("failed to parse session info: %w", err)
   107→		}
   108→		input.SessionID = raw.SessionID
   109→		input.SessionRef = raw.TranscriptPath
   110→		// Store Gemini-specific fields in RawData
   111→		input.RawData["cwd"] = raw.Cwd
   112→		input.RawData["hook_event_name"] = raw.HookEventName
   113→		if raw.Source != "" {
   114→			input.RawData["source"] = raw.Source
   115→		}
   116→		if raw.Reason != "" {
   117→			input.RawData["reason"] = raw.Reason
   118→		}
   119→
   120→	case agent.HookUserPromptSubmit:
   121→		// BeforeAgent is Gemini's equivalent to Claude's UserPromptSubmit
   122→		// It provides the user's prompt in the "prompt" field
   123→		var raw agentHookInputRaw
   124→		if err := json.Unmarshal(data, &raw); err != nil {
   125→			return nil, fmt.Errorf("failed to parse agent hook input: %w", err)
   126→		}
   127→		input.SessionID = raw.SessionID
   128→		input.SessionRef = raw.TranscriptPath
   129→		input.RawData["cwd"] = raw.Cwd
   130→		input.RawData["hook_event_name"] = raw.HookEventName
   131→		if raw.Prompt != "" {
   132→			input.UserPrompt = raw.Prompt
   133→			input.RawData["prompt"] = raw.Prompt
   134→		}
   135→
   136→	case agent.HookPreToolUse, agent.HookPostToolUse:
   137→		var raw toolHookInputRaw
   138→		if err := json.Unmarshal(data, &raw); err != nil {
   139→			return nil, fmt.Errorf("failed to parse tool hook input: %w", err)
   140→		}
   141→		input.SessionID = raw.SessionID
   142→		input.SessionRef = raw.TranscriptPath
   143→		input.ToolName = raw.ToolName
   144→		input.ToolInput = raw.ToolInput
   145→		if hookType == agent.HookPostToolUse {
   146→			input.ToolResponse = raw.ToolResponse
   147→		}
   148→		input.RawData["cwd"] = raw.Cwd
   149→		input.RawData["hook_event_name"] = raw.HookEventName
   150→	}
   151→
   152→	return input, nil
   153→}
