   227→// WriteSession writes a session to Gemini's storage (JSON transcript file).
   228→// Uses the NativeData field which contains raw JSON bytes.
   229→func (g *GeminiCLIAgent) WriteSession(session *agent.AgentSession) error {
   230→	if session == nil {
   231→		return errors.New("session is nil")
   232→	}
   233→
   234→	// Verify this session belongs to Gemini CLI
   235→	if session.AgentName != "" && session.AgentName != g.Name() {
   236→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, g.Name())
   237→	}
   238→
   239→	if session.SessionRef == "" {
   240→		return errors.New("session reference (transcript path) is required")
   241→	}
   242→
   243→	if len(session.NativeData) == 0 {
   244→		return errors.New("session has no native data to write")
   245→	}
   246→
   247→	// Write the raw JSON data
   248→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
   249→		return fmt.Errorf("failed to write transcript: %w", err)
   250→	}
   251→
   252→	return nil
   253→}
