   635→	store, err := s.getCheckpointStore()
   636→	if err != nil {
   637→		return fmt.Errorf("failed to get checkpoint store: %w", err)
   638→	}
   639→
   640→	// Read checkpoint summary to get session count
   641→	summary, err := store.ReadCommitted(context.Background(), point.CheckpointID)
   642→	if err != nil {
   643→		return fmt.Errorf("failed to read checkpoint: %w", err)
   644→	}
   645→	if summary == nil {
   646→		return fmt.Errorf("checkpoint not found: %s", point.CheckpointID)
   647→	}
   648→
   649→	// Get repo root for agent session directory lookup
   650→	repoRoot, err := paths.RepoRoot()
   651→	if err != nil {
   652→		return fmt.Errorf("failed to get repository root: %w", err)
   653→	}
   654→
   655→	sessionDir, err := ag.GetSessionDir(repoRoot)
   656→	if err != nil {
   657→		return fmt.Errorf("failed to get agent session directory: %w", err)
   658→	}
   659→
   660→	// Ensure session directory exists
   661→	if err := os.MkdirAll(sessionDir, 0o750); err != nil {
   662→		return fmt.Errorf("failed to create agent session directory: %w", err)
   663→	}
   664→
   665→	// Check for newer local logs if not forcing
   666→	if !force {
   667→		sessions := s.classifySessionsForRestore(context.Background(), sessionDir, ag, store, point.CheckpointID, summary)
   668→		hasConflicts := false
   669→		for _, sess := range sessions {
   670→			if sess.Status == StatusLocalNewer {
   671→				hasConflicts = true
   672→				break
   673→			}
   674→		}
   675→		if hasConflicts {
   676→			shouldOverwrite, promptErr := PromptOverwriteNewerLogs(sessions)
   677→			if promptErr != nil {
   678→				return promptErr
   679→			}
   680→			if !shouldOverwrite {
   681→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session logs preserved.\n")
   682→				return nil
   683→			}
   684→		}
   685→	}
   686→
   687→	// Count sessions to restore
   688→	totalSessions := len(summary.Sessions)
   689→	if totalSessions > 1 {
   690→		fmt.Fprintf(os.Stderr, "Restoring %d sessions from checkpoint:\n", totalSessions)
   691→	}
   692→
   693→	// Restore all sessions (oldest to newest, using 0-based indexing)
   694→	for i := range totalSessions {
   695→		content, readErr := store.ReadSessionContent(context.Background(), point.CheckpointID, i)
   696→		if readErr != nil {
   697→			fmt.Fprintf(os.Stderr, "  Warning: failed to read session %d: %v\n", i, readErr)
   698→			continue
   699→		}
