   718→			isLatest := i == totalSessions-1
   719→			if promptPreview != "" {
   720→				if isLatest {
   721→					fmt.Fprintf(os.Stderr, "  Session %d (latest): %s\n", i+1, promptPreview)
   722→				} else {
   723→					fmt.Fprintf(os.Stderr, "  Session %d: %s\n", i+1, promptPreview)
   724→				}
   725→			}
   726→			fmt.Fprintf(os.Stderr, "    Writing to: %s\n", sessionFile)
   727→		} else {
   728→			fmt.Fprintf(os.Stderr, "Writing transcript to: %s\n", sessionFile)
   729→		}
