   847→// ClassifyTimestamps determines the restore status based on local and checkpoint timestamps.
   848→func ClassifyTimestamps(localTime, checkpointTime time.Time) SessionRestoreStatus {
   849→	// Local file doesn't exist (no timestamp found)
   850→	if localTime.IsZero() {
   851→		return StatusNew
   852→	}
   853→
   854→	// Can't determine checkpoint time - treat as new/safe
   855→	if checkpointTime.IsZero() {
   856→		return StatusNew
   857→	}
   858→
   859→	// Compare timestamps
   860→	if localTime.After(checkpointTime) {
   861→		return StatusLocalNewer
   862→	}
   863→	if checkpointTime.After(localTime) {
   864→		return StatusCheckpointNewer
   865→	}
   866→	return StatusUnchanged
   867→}
