   869→// StatusToText returns a human-readable status string.
   870→func StatusToText(status SessionRestoreStatus) string {
   871→	switch status {
   872→	case StatusNew:
   873→		return "(new)"
   874→	case StatusUnchanged:
   875→		return "(unchanged)"
   876→	case StatusCheckpointNewer:
   877→		return "(checkpoint is newer)"
   878→	case StatusLocalNewer:
   879→		return "(local is newer)" // shouldn't appear in non-conflict list
   880→	default:
   881→		return ""
   882→	}
   883→}
