   885→// PromptOverwriteNewerLogs asks the user for confirmation to overwrite local
   886→// session logs that have newer timestamps than the checkpoint versions.
   887→func PromptOverwriteNewerLogs(sessions []SessionRestoreInfo) (bool, error) {
   888→	// Separate conflicting and non-conflicting sessions
   889→	var conflicting, nonConflicting []SessionRestoreInfo
   890→	for _, s := range sessions {
   891→		if s.Status == StatusLocalNewer {
   892→			conflicting = append(conflicting, s)
   893→		} else {
   894→			nonConflicting = append(nonConflicting, s)
   895→		}
   896→	}
   897→
   898→	fmt.Fprintf(os.Stderr, "\nWarning: Local session log(s) have newer entries than the checkpoint:\n")
   899→	for _, info := range conflicting {
   900→		// Show prompt if available, otherwise fall back to session ID
   901→		if info.Prompt != "" {
   902→			fmt.Fprintf(os.Stderr, "  \"%s\"\n", info.Prompt)
   903→		} else {
   904→			fmt.Fprintf(os.Stderr, "  Session: %s\n", info.SessionID)
   905→		}
   906→		fmt.Fprintf(os.Stderr, "    Local last entry:      %s\n", info.LocalTime.Local().Format("2006-01-02 15:04:05"))
   907→		fmt.Fprintf(os.Stderr, "    Checkpoint last entry: %s\n", info.CheckpointTime.Local().Format("2006-01-02 15:04:05"))
   908→	}
   909→
   910→	// Show non-conflicting sessions with their status
   911→	if len(nonConflicting) > 0 {
   912→		fmt.Fprintf(os.Stderr, "\nThese other session(s) will also be restored:\n")
   913→		for _, info := range nonConflicting {
   914→			statusText := StatusToText(info.Status)
   915→			if info.Prompt != "" {
   916→				fmt.Fprintf(os.Stderr, "  \"%s\" %s\n", info.Prompt, statusText)
   917→			} else {
   918→				fmt.Fprintf(os.Stderr, "  Session: %s %s\n", info.SessionID, statusText)
   919→			}
   920→		}
   921→	}
   922→
   923→	fmt.Fprintf(os.Stderr, "\nOverwriting will lose the newer local entries.\n\n")
   924→
   925→	var confirmed bool
   926→	form := huh.NewForm(
   927→		huh.NewGroup(
   928→			huh.NewConfirm().
   929→				Title("Overwrite local session logs with checkpoint versions?").
   930→				Value(&confirmed),
   931→		),
   932→	)
   933→	if isAccessibleMode() {
   934→		form = form.WithAccessible(true)
   935→	}
   936→
   937→	if err := form.Run(); err != nil {
   938→		if errors.Is(err, huh.ErrUserAborted) {
   939→			return false, nil
   940→		}
   941→		return false, fmt.Errorf("failed to get confirmation: %w", err)
   942→	}
   943→
   944→	return confirmed, nil
   945→}
