		if result != expected {
			t.Errorf("ResolveSessionFile() = %q, want %q", result, expected)
		}
	})

	t.Run("handles short session ID", func(t *testing.T) {
		t.Parallel()
		tmpDir := t.TempDir()
		ag := &GeminiCLIAgent{}

