   113→		sort.Slice(allPoints, func(i, j int) bool {
   114→			return allPoints[i].Date.After(allPoints[j].Date)
   115→		})
   116→
   117→		// Re-trim to limit
   118→		if len(allPoints) > limit {
   119→			allPoints = allPoints[:limit]
