   614→// RestoreLogsOnly restores session logs from a logs-only rewind point.
   615→// This fetches the transcript from entire/checkpoints/v1 and writes it to the agent's session directory.
   616→// Does not modify the working directory.
   617→// When multiple sessions were condensed to the same checkpoint, ALL sessions are restored.
   618→// If force is false, prompts for confirmation when local logs have newer timestamps.
   619→func (s *ManualCommitStrategy) RestoreLogsOnly(point RewindPoint, force bool) error {
   620→	if !point.IsLogsOnly {
   621→		return errors.New("not a logs-only rewind point")
   622→	}
   623→
   624→	if point.CheckpointID.IsEmpty() {
   625→		return errors.New("missing checkpoint ID")
   626→	}
   627→
   628→	// Resolve agent from checkpoint metadata (fall back to Claude for old checkpoints)
   629→	ag, err := resolveAgentForRewind(point.Agent)
   630→	if err != nil {
   631→		return fmt.Errorf("failed to resolve agent: %w", err)
   632→	}
   633→
   634→	// Get checkpoint store
   635→	store, err := s.getCheckpointStore()
   636→	if err != nil {
   637→		return fmt.Errorf("failed to get checkpoint store: %w", err)
   638→	}
   639→
   640→	// Read checkpoint summary to get session count
   641→	summary, err := store.ReadCommitted(context.Background(), point.CheckpointID)
   642→	if err != nil {
   643→		return fmt.Errorf("failed to read checkpoint: %w", err)
   644→	}
   645→	if summary == nil {
   646→		return fmt.Errorf("checkpoint not found: %s", point.CheckpointID)
   647→	}
   648→
   649→	// Get repo root for agent session directory lookup
   650→	repoRoot, err := paths.RepoRoot()
   651→	if err != nil {
   652→		return fmt.Errorf("failed to get repository root: %w", err)
   653→	}
   654→
   655→	sessionDir, err := ag.GetSessionDir(repoRoot)
   656→	if err != nil {
   657→		return fmt.Errorf("failed to get agent session directory: %w", err)
   658→	}
   659→
   660→	// Ensure session directory exists
   661→	if err := os.MkdirAll(sessionDir, 0o750); err != nil {
   662→		return fmt.Errorf("failed to create agent session directory: %w", err)
   663→	}
   664→
   665→	// Check for newer local logs if not forcing
   666→	if !force {
   667→		sessions := s.classifySessionsForRestore(context.Background(), sessionDir, ag, store, point.CheckpointID, summary)
   668→		hasConflicts := false
   669→		for _, sess := range sessions {
   670→			if sess.Status == StatusLocalNewer {
   671→				hasConflicts = true
   672→				break
   673→			}
   674→		}
   675→		if hasConflicts {
   676→			shouldOverwrite, promptErr := PromptOverwriteNewerLogs(sessions)
   677→			if promptErr != nil {
   678→				return promptErr
   679→			}
   680→			if !shouldOverwrite {
   681→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session logs preserved.\n")
   682→				return nil
   683→			}
   684→		}
   685→	}
   686→
   687→	// Count sessions to restore
   688→	totalSessions := len(summary.Sessions)
   689→	if totalSessions > 1 {
   690→		fmt.Fprintf(os.Stderr, "Restoring %d sessions from checkpoint:\n", totalSessions)
   691→	}
   692→
   693→	// Restore all sessions (oldest to newest, using 0-based indexing)
   694→	for i := range totalSessions {
   695→		content, readErr := store.ReadSessionContent(context.Background(), point.CheckpointID, i)
   696→		if readErr != nil {
   697→			fmt.Fprintf(os.Stderr, "  Warning: failed to read session %d: %v\n", i, readErr)
   698→			continue
   699→		}
   700→		if content == nil || len(content.Transcript) == 0 {
   701→			continue
   702→		}
   703→
   704→		sessionID := content.Metadata.SessionID
   705→		if sessionID == "" {
   706→			// Fallback: can't identify session without ID
   707→			fmt.Fprintf(os.Stderr, "  Warning: session %d has no session ID, skipping\n", i)
   708→			continue
   709→		}
   710→
   711→		agentSessionID := ag.ExtractAgentSessionID(sessionID)
   712→		sessionFile := ag.ResolveSessionFile(sessionDir, agentSessionID)
   713→
   714→		// Get first prompt for display
   715→		promptPreview := ExtractFirstPrompt(content.Prompts)
   716→
   717→		if totalSessions > 1 {
   718→			isLatest := i == totalSessions-1
   719→			if promptPreview != "" {
   720→				if isLatest {
   721→					fmt.Fprintf(os.Stderr, "  Session %d (latest): %s\n", i+1, promptPreview)
   722→				} else {
   723→					fmt.Fprintf(os.Stderr, "  Session %d: %s\n", i+1, promptPreview)
   724→				}
   725→			}
   726→			fmt.Fprintf(os.Stderr, "    Writing to: %s\n", sessionFile)
   727→		} else {
   728→			fmt.Fprintf(os.Stderr, "Writing transcript to: %s\n", sessionFile)
   729→		}
   730→
   731→		if writeErr := os.WriteFile(sessionFile, content.Transcript, 0o600); writeErr != nil {
   732→			if totalSessions > 1 {
   733→				fmt.Fprintf(os.Stderr, "    Warning: failed to write transcript: %v\n", writeErr)
   734→				continue
   735→			}
   736→			return fmt.Errorf("failed to write transcript: %w", writeErr)
   737→		}
   738→	}
   739→
   740→	return nil
   741→}
